<div class="page-header"><div><h2 class="page-title">Relations post / categorie</h2><p class="page-meta">Associez les articles aux categories.</p></div><div class="page-actions"><a class="btn btn-primary"href="/admin/post-categories/create">Nouvelle relation</a></div></div><?php if(!empty($relations)): ?><div class="card table-card"><table class="admin-table"><thead><tr><th>Post ID</th><th>Article</th><th>Categorie ID</th><th>Categorie</th><th>Actions</th></tr></thead><tbody><?php foreach($relations as $relation): ?><tr><td><?=(int)$relation['post_id']?></td><td><?=htmlspecialchars($relation['post_title'])?></td><td><?=(int)$relation['category_id']?></td><td><?=htmlspecialchars($relation['category_name'])?></td><td><div class="table-actions"><a class="btn btn-ghost"href="/admin/post-categories/<?=(int)$relation['post_id']?>/<?=(int)$relation['category_id']?>/edit">Modifier</a><form action="/admin/post-categories/<?=(int)$relation['post_id']?>/<?=(int)$relation['category_id']?>/delete"method="post"onsubmit='return confirm("Supprimer cette relation ?")'><button class="btn btn-danger"type="submit">Supprimer</button></form></div></td></tr><?php endforeach; ?></tbody></table></div><?php else: ?><p class="page-meta">Aucune relation post/categorie enregistree.</p><?php endif; ?>